func CronJobSpecDefaults(spec *batchv1.CronJobSpec) {
	if spec.ConcurrencyPolicy == "" {
		spec.ConcurrencyPolicy = batchv1.AllowConcurrent
	}
	// ... cronjob-level defaults ...
	JobSpecDefaults(&spec.JobTemplate.Spec)
	PodSpecDefaults(&spec.JobTemplate.Spec.Template.Spec)
}

func DeploymentSpecDefaults(spec *appsv1.DeploymentSpec) {
	if spec.RevisionHistoryLimit == nil {
		v := int32(10)
		spec.RevisionHistoryLimit = &v
	}
	// ... deployment-level defaults ...
	PodSpecDefaults(&spec.Template.Spec)
}

func TestDeploymentSpecDefaults(t *testing.T) {
	g := NewGomegaWithT(t)
	spec := &appsv1.DeploymentSpec{...}
	DeploymentSpecDefaults(spec)
	g.Expect(spec.RevisionHistoryLimit).NotTo(BeNil())
	g.Expect(*spec.RevisionHistoryLimit).To(Equal(int32(10)))
	// ...
}

func TestDeploymentSpecDefaults_preservesExplicitValues(t *testing.T) {
	g := NewGomegaWithT(t)
	revisionLimit := int32(5)
	spec := &appsv1.DeploymentSpec{RevisionHistoryLimit: &revisionLimit, ...}
	DeploymentSpecDefaults(spec)
	g.Expect(*spec.RevisionHistoryLimit).To(Equal(int32(5)))
	// ...
}
